const esc=s=>String(s??'').replace(/[&<>'"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c]));
async function api(url,opt={}){const r=await fetch(url,opt),j=await r.json();if(!j.ok)throw new Error(j.error||'Falha na opera├з├гo');return j}function post(action,data={},file=null){const f=new FormData();f.append('csrf',SC.csrf);f.append('action',action);Object.entries(data).forEach(([k,v])=>f.append(k,v));if(file)f.append('attachment',file);return api('suporte_chat.php',{method:'POST',body:f})}
function setSupportView(view){SC.view=view;document.querySelectorAll('.sc-view').forEach(x=>{const active=x.id==='view-'+view;x.classList.toggle('active',active);if(active)x.removeAttribute('hidden');else x.setAttribute('hidden','')});document.querySelectorAll('.sc-tab').forEach(x=>x.classList.toggle('active',(x.getAttribute('href')||'').includes('view='+view)));if(view==='crm')renderCrmBoard()}
function crmMatch(c,cond){cond=String(cond||'').trim();if(!cond)return true;const [k,v]=cond.split('=').map(x=>x.trim());return String(c[k]??'')===v}
function crmApplyCondition(c,stage){c.stage=stage.id||c.stage||'agent';c.status=stage.id==='done'?'closed':(stage.id==='human'?'pending':'open');String(stage.condition||'').split(/[,&;]/).forEach(part=>{const [k,v]=part.split('=').map(x=>String(x||'').trim());if(k&&v)c[k]=v})}
function crmSummary(c){const notes=String(c.notes||'').split('\n').reverse().find(x=>x.includes('Agente transferiu para humano:'));if(notes)return notes.replace('Agente transferiu para humano:','').trim().slice(0,150);return String(c.last_body||'Atendimento iniciado').slice(0,150)}
function bindCrmBoard(){let dragging=null,dragMoved=false;document.querySelectorAll('.sc-card').forEach(card=>{card.ondragstart=e=>{dragging=card.dataset.id;dragMoved=false;e.dataTransfer.setData('text/plain',dragging);card.classList.add('dragging');e.dataTransfer.effectAllowed='move'};card.ondragend=()=>{card.classList.remove('dragging');document.querySelectorAll('.sc-col').forEach(c=>c.classList.remove('drag-over'));setTimeout(()=>{dragging=null;dragMoved=false},0)};card.onclick=()=>{if(dragMoved)return;const id=+card.dataset.id;setSupportView('live');history.replaceState(null,'','suporte_chat.php?view=live&conversation_id='+id);selectConversation(id)}});document.querySelectorAll('.sc-col').forEach(col=>{col.ondragover=e=>{e.preventDefault();dragMoved=true;col.classList.add('drag-over')};col.ondragleave=()=>col.classList.remove('drag-over');col.ondrop=async e=>{e.preventDefault();dragMoved=true;col.classList.remove('drag-over');const id=+(dragging||e.dataTransfer.getData('text/plain'));const stage=CRM_STAGES.find(s=>String(s.id)===col.dataset.stage);const conv=CRM_CONVERSATIONS.find(c=>+c.id===id);if(!stage||!conv)return;crmApplyCondition(conv,stage);renderCrmBoard();try{await post('move_crm',{conversation_id:id,stage_id:stage.id,condition:stage.condition||''});loadConversations()}catch(err){alert(err.message);location.reload()}}})}
function renderCrmBoard(){if(SC.view!=='crm')return;const el=document.querySelector('#view-crm .sc-panel');if(!el)return;el.innerHTML='<h2>CRM de suporte</h2><p class="text-muted text-sm">Arraste os cards entre as colunas. O resumo mostra o assunto e, quando houver, o motivo da transferencia para humano.</p><div class="sc-kanban">'+CRM_STAGES.map(s=>{const items=CRM_CONVERSATIONS.filter(c=>crmMatch(c,s.condition));return `<section class="sc-col" data-stage="${esc(s.id)}"><h3>${esc(s.label)} <span>${items.length}</span></h3>${items.map(c=>`<article class="sc-card" draggable="true" data-id="${c.id}"><strong>${esc(c.user_name)}</strong><small>${esc(c.user_email||'')}</small><p class="reason">${esc(crmSummary(c))}</p><div class="meta"><span>${esc(c.priority||'normal')}</span><span>${fmt(c.last_message_at)}</span></div></article>`).join('')||'<div class="sc-empty" style="padding:26px;color:#64748b">Sem atendimentos.</div>'}</section>`}).join('')+'</div>';bindCrmBoard()}
setSupportView(SC.view);
function fieldOptionByPath(path){return AGENT_FIELD_OPTIONS.find(o=>o.path===path)||null}
function keyFromPath(path){return String(path||'').replace(/\.\d+\./g,'.').replace(/[^a-z0-9]+/gi,'_').replace(/^_+|_+$/g,'').toLowerCase()}
function renderAgentFieldOptions(){if(!window.agentPayloadFields)return;agentPayloadFields.innerHTML=AGENT_FIELD_OPTIONS.map(o=>`<option value="${esc(o.path)}" label="${esc(o.label)}">${esc(o.label)} - ${esc(o.description||'')}</option>`).join('')}
function applyAgentField(row,input){const i=+row.dataset.i,opt=fieldOptionByPath(input.value);AGENT_VARIABLES[i].path=input.value;if(!opt)return;if(!AGENT_VARIABLES[i].label)AGENT_VARIABLES[i].label=opt.label||'';if(!AGENT_VARIABLES[i].description)AGENT_VARIABLES[i].description=opt.description||'';if(!AGENT_VARIABLES[i].key)AGENT_VARIABLES[i].key=keyFromPath(opt.path);renderAgentVars()}
function renderAgentVars(){if(!window.agentVarRows)return;renderAgentFieldOptions();agentVarRows.innerHTML=AGENT_VARIABLES.map((v,i)=>`<div class="sc-var-row" data-i="${i}"><input class="sc-search" data-k="key" placeholder="chave" value="${esc(v.key||'')}"><input class="sc-search" data-k="label" placeholder="rotulo" value="${esc(v.label||'')}"><input class="sc-search" data-k="path" list="agentPayloadFields" placeholder="buscar campo do sistema" value="${esc(v.path||'')}"><input class="sc-search" data-k="description" placeholder="o que significa" value="${esc(v.description||'')}"><button type="button" title="Remover">x</button></div>`).join('');agentVarRows.querySelectorAll('.sc-var-row').forEach(row=>{row.querySelectorAll('input').forEach(input=>input.oninput=()=>{AGENT_VARIABLES[+row.dataset.i][input.dataset.k]=input.value});const pathInput=row.querySelector('[data-k="path"]');pathInput.onchange=()=>applyAgentField(row,pathInput);row.querySelector('button').onclick=()=>{AGENT_VARIABLES.splice(+row.dataset.i,1);renderAgentVars()}})}
function agentVarsJson(){return JSON.stringify(AGENT_VARIABLES.filter(v=>(v.key||'').trim()&&(v.path||'').trim()).map(v=>({key:(v.key||'').trim(),label:(v.label||'').trim(),path:(v.path||'').trim(),description:(v.description||'').trim()})))}
