function messageHtml(m,studentView=false){const own=studentView?m.sender_type==='student':m.sender_type!=='student',cls=own?'own':(m.sender_type==='bot'?'bot':'student'),url=m.local_url?esc(m.local_url):'../public/'+esc(m.attachment_url||''),messageId=m.id?esc(m.id):'';let content=esc(m.body||'').replace(/\n/g,'<br>'),meta={};try{meta=JSON.parse(m.metadata_json||'{}')}catch(e){}if(m.message_type==='image')content=`<img src="${url}" alt="Imagem enviada">`+content;if(m.message_type==='video')content=`<video controls preload="metadata" src="${url}"></video>`+content;if(m.message_type==='audio')content=`<audio controls preload="metadata" src="${url}"></audio>`+content;if(m.message_type==='file')content=`<a class="sc-file" target="_blank" href="${url}">ЁЯУД ${esc(m.attachment_name)}</a>`+content;if(Array.isArray(meta.buttons)&&meta.buttons.length)content+=`<div class="sc-msg-buttons">${meta.buttons.map(b=>`<a class="sc-msg-button" target="_blank" rel="noopener" href="${esc(b.url||'#')}">${esc(b.label||'Abrir')}</a>`).join('')}</div>`;return `<div class="sc-msg ${cls}" ${messageId?`data-message-id="${messageId}"`:''}>${!studentView&&m.sender_type!=='student'?`<div class="sign">${esc(m.sender_name||'Equipe')}</div>`:''}${studentView&&m.sender_type!=='student'?`<div class="sign">${esc(m.sender_name||'Suporte')}</div>`:''}${content}<span class="time">${fmt(m.created_at)} ${own?'тЬУтЬУ':''}</span></div>`}
